import React, { useState } from 'react';
import './App.css';
import FileUpload from './components/FileUpload';
import Dashboard from './components/Dashboard';
import InvestmentAdvice from './components/InvestmentAdvice';
import ConnectUPI from './components/ConnectUPI';
import axios from 'axios';

function App() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [showInvestmentAdvice, setShowInvestmentAdvice] = useState(false);
  const [showUPISync, setShowUPISync] = useState(false);

  const handleFileUpload = async (file) => {
    setLoading(true);
    setError(null);
    setData(null);

    const formData = new FormData();
    formData.append('file', file);

    try {
      const response = await axios.post('/api/analyze', formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });

      setData(response.data);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to process file');
      console.error('Upload error:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setData(null);
    setError(null);
    setShowInvestmentAdvice(false);
    setShowUPISync(false);
  };

  const handleShowInvestmentAdvice = () => {
    setShowInvestmentAdvice(true);
    setShowUPISync(false);
  };

  const handleShowUPISync = () => {
    setShowUPISync(true);
    setShowInvestmentAdvice(false);
  };

  const handleBackToDashboard = () => {
    setShowInvestmentAdvice(false);
    setShowUPISync(false);
  };

  return (
    <div className="App">
      <header className="App-header">
        <h1>💰 Finance Tracker</h1>
        <p>AI-Powered Transaction Analysis</p>
      </header>

      <main className="App-main">
        {!data && !loading && !showUPISync && (
          <FileUpload 
            onFileUpload={handleFileUpload} 
            onConnectUPI={handleShowUPISync}
            error={error} 
          />
        )}

        {loading && (
          <div className="loading-container">
            <div className="spinner"></div>
            <p>Analyzing your transactions...</p>
          </div>
        )}

        {data && !loading && !showInvestmentAdvice && !showUPISync && (
          <Dashboard 
            data={data} 
            onReset={handleReset}
            onShowInvestmentAdvice={handleShowInvestmentAdvice}
          />
        )}

        {data && !loading && showInvestmentAdvice && (
          <InvestmentAdvice 
            financialData={data}
            onBack={handleBackToDashboard}
          />
        )}

        {showUPISync && (
          <ConnectUPI 
            onBack={handleBackToDashboard}
            onConnected={() => {
              // After successful connection, show dashboard
              setShowUPISync(false);
              // Optionally fetch and display UPI transaction data
            }}
          />
        )}
      </main>

      <footer className="App-footer">
        <p>Powered by Machine Learning (TF-IDF + Linear SVM)</p>
      </footer>
    </div>
  );
}

export default App;
